import{$ as e,A as t,B as n,V as r}from"./chunks/framework.qypF2UUz.js";var i=JSON.parse(`{"title":"消息场景","description":"","frontmatter":{"prev":{"text":"项目结构","link":"/guide/structure"},"next":{"text":"插件开发","link":"/plugins/introduction"}},"headers":[],"relativePath":"guide/scenarios.md","filePath":"guide/scenarios.md","lastUpdated":1784193220000}`),a={name:`guide/scenarios.md`};function o(t,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[r(`<h1 id="消息场景" tabindex="-1">消息场景 <a class="header-anchor" href="#消息场景" aria-label="Permalink to “消息场景”">​</a></h1><p>机器人支持以下 4 种消息场景：</p><h2 id="qq-单聊-c2c-message-create" tabindex="-1">QQ 单聊 (C2C_MESSAGE_CREATE) <a class="header-anchor" href="#qq-单聊-c2c-message-create" aria-label="Permalink to “QQ 单聊 (C2C_MESSAGE_CREATE)”">​</a></h2><p>用户私聊机器人时触发。支持完整功能：</p><ul><li>内置命令（<code>ping</code>、<code>帮助</code>、<code>状态</code>、<code>注销</code>）</li><li>角色命令（<code>角色 列表</code>、<code>角色 切换</code>...）</li><li>AI 对话（直接发送消息即可触发）</li><li><code>#消息</code> 格式显式触发 AI 对话</li></ul><h3 id="对话上下文" tabindex="-1">对话上下文 <a class="header-anchor" href="#对话上下文" aria-label="Permalink to “对话上下文”">​</a></h3><p>单聊中会自动维护每用户的对话上下文（最多 20 条），可通过发送 <code>注销</code> 清除。</p><h2 id="qq-群聊-机器人-group-at-message-create" tabindex="-1">QQ 群聊@机器人 (GROUP_AT_MESSAGE_CREATE) <a class="header-anchor" href="#qq-群聊-机器人-group-at-message-create" aria-label="Permalink to “QQ 群聊@机器人 (GROUP_AT_MESSAGE_CREATE)”">​</a></h2><p>用户在群中 @机器人 时触发。支持：</p><ul><li>内置命令（<code>ping</code>、<code>帮助</code>、<code>状态</code>）</li><li>角色命令</li><li>插件命令（<code>签到</code>、<code>天气 北京</code>、<code>ping 1.1.1.1</code> 等）</li><li><strong>不支持</strong> AI 对话</li></ul><p>命令前缀 <code>+</code> 或 <code>/</code> 会被自动去除，例如 <code>+/签到</code> 等价于 <code>签到</code>。</p><h2 id="qq-群聊全量消息-group-message-create" tabindex="-1">QQ 群聊全量消息 (GROUP_MESSAGE_CREATE) <a class="header-anchor" href="#qq-群聊全量消息-group-message-create" aria-label="Permalink to “QQ 群聊全量消息 (GROUP_MESSAGE_CREATE)”">​</a></h2><p>群内所有消息（私域机器人可接收）。功能与 @消息 相同，但：</p><ul><li>自动过滤 @机器人的前缀</li><li>跳过 <code>affection</code> 插件（避免频繁查询）</li><li>仅 <code>#</code> 前缀消息会提示未找到命令</li></ul><h2 id="频道消息" tabindex="-1">频道消息 <a class="header-anchor" href="#频道消息" aria-label="Permalink to “频道消息”">​</a></h2><p>支持两种频道事件：</p><table tabindex="0"><thead><tr><th style="text-align:left;">事件</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>DIRECT_MESSAGE_CREATE</code></td><td style="text-align:left;">频道私信，功能类似 QQ 单聊，支持 AI 对话</td></tr><tr><td style="text-align:left;"><code>AT_MESSAGE_CREATE</code></td><td style="text-align:left;">频道 @机器人，类似群聊@机器人，不支持 AI 对话</td></tr></tbody></table><h3 id="消息处理优先级" tabindex="-1">消息处理优先级 <a class="header-anchor" href="#消息处理优先级" aria-label="Permalink to “消息处理优先级”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>内置命令 &gt; 角色命令 &gt; 插件命令 &gt; AI 对话(仅限单聊/频道私信)</span></span></code></pre></div><h2 id="事件处理概览" tabindex="-1">事件处理概览 <a class="header-anchor" href="#事件处理概览" aria-label="Permalink to “事件处理概览”">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">客户端方法</th><th style="text-align:left;">对应事件</th><th style="text-align:center;">AI 支持</th></tr></thead><tbody><tr><td style="text-align:left;"><code>on_c2c_message_create</code></td><td style="text-align:left;">QQ 单聊</td><td style="text-align:center;">✅</td></tr><tr><td style="text-align:left;"><code>on_group_at_message_create</code></td><td style="text-align:left;">QQ 群聊@</td><td style="text-align:center;">❌</td></tr><tr><td style="text-align:left;"><code>on_group_message_create</code></td><td style="text-align:left;">群聊全量</td><td style="text-align:center;">❌</td></tr><tr><td style="text-align:left;"><code>on_direct_message_create</code></td><td style="text-align:left;">频道私信</td><td style="text-align:center;">✅</td></tr><tr><td style="text-align:left;"><code>on_at_message_create</code></td><td style="text-align:left;">频道@</td><td style="text-align:center;">❌</td></tr><tr><td style="text-align:left;"><code>on_group_add_robot</code></td><td style="text-align:left;">机器人入群</td><td style="text-align:center;">—</td></tr><tr><td style="text-align:left;"><code>on_group_del_robot</code></td><td style="text-align:left;">机器人退群</td><td style="text-align:center;">—</td></tr></tbody></table>`,21)]])}var s=t(a,[[`render`,o]]);export{i as __pageData,s as default};